import { resolve } from 'node:path';
import { defineConfig } from 'vitest/config';

export default defineConfig({
  resolve: {
    alias: {
      '@': resolve(__dirname, 'src'),
    },
  },
  test: {
    include: ['src/**/*.test.ts'],
    testTimeout: 30_000,
    coverage: {
      include: ['src/**/*.ts'],
      provider: 'v8',
    },
  },
});

import { drizzle } from 'drizzle-orm/postgres-js';
import postgres from 'postgres';
import * as schema from '@/db/schema';

const TEST_DATABASE_URL =
  process.env.DATABASE_URL ??
  'REDACTED';

/**
 * Run a test callback inside a transaction that is always rolled back.
 * Each test gets a clean slate without polluting the shared database.
 */
export async function withTestDb<T>(
  fn: (db: ReturnType<typeof drizzle<typeof schema>>) => Promise<T>,
): Promise<T> {
  const sql = postgres(TEST_DATABASE_URL, { max: 1 });
  const db = drizzle(sql, { schema });

  try {
    return await db.transaction(async (tx) => {
      const result = await fn(tx as unknown as typeof db);
      // Always rollback — the throw is the mechanism, not an error
      throw { __rollback: true, result };
    });
  } catch (e: unknown) {
    if (
      e &&
      typeof e === 'object' &&
      '__rollback' in e &&
      (e as { __rollback: boolean }).__rollback
    ) {
      return (e as { result: T }).result;
    }
    throw e;
  } finally {
    await sql.end();
  }
}

import { sql } from 'drizzle-orm';
import { describe, expect, it } from 'vitest';
import { withTestDb } from './with-test-db';

describe('test infrastructure', () => {
  it('connects to the database and runs a query', async () => {
    await withTestDb(async (db) => {
      const rows = await db.execute(sql`SELECT 1 AS ok`);
      expect(rows).toHaveLength(1);
    });
  });

  it('rolls back writes between tests', async () => {
    const tableName = `_smoke_test_${Date.now()}`;

    await withTestDb(async (db) => {
      await db.execute(
        sql.raw(`CREATE TEMP TABLE ${tableName} (id serial PRIMARY KEY)`),
      );
      await db.execute(sql.raw(`INSERT INTO ${tableName} DEFAULT VALUES`));
      const rows = await db.execute(
        sql.raw(`SELECT count(*)::int AS c FROM ${tableName}`),
      );
      expect(rows[0].c).toBe(1);
    });
  });
});

