import { cache } from 'react';
import {
  type CursorPlugin,
  HttpCursorMarketplaceUpstream,
} from './cursor-upstream';

const upstream = new HttpCursorMarketplaceUpstream();

/**
 * Request-scoped fetch of the full Cursor plugin catalog. The Cursor API
 * returns ~140 plugins in a single call, so we cache the full list and let
 * callers (detail page / owner page / leaderboard) filter in-memory.
 */
export const getCursorPlugins = cache(async (): Promise<CursorPlugin[]> => {
  return upstream.listPlugins();
});

/**
 * Find a plugin by owner + Cursor plugin name. Owner is the GitHub owner
 * derived from `repositoryUrl`, not the Cursor publisher.
 */
export async function findCursorPlugin(
  owner: string,
  name: string
): Promise<CursorPlugin | null> {
  const plugins = await getCursorPlugins();
  return (
    plugins.find((plugin) => plugin.owner === owner && plugin.name === name) ??
    null
  );
}

/**
 * List all plugins owned by a given GitHub owner.
 */
export async function listCursorPluginsByOwner(
  owner: string
): Promise<CursorPlugin[]> {
  const plugins = await getCursorPlugins();
  return plugins.filter((plugin) => plugin.owner === owner);
}

import { InstallCommand } from '@/components/skills/install-command';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import {
  Breadcrumb,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbList,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from '@/components/ui/breadcrumb';
import { constructMetadata } from '@/lib/metadata';
import { findCursorPlugin } from '@/skills/get-cursor-upstream';
import { ExternalLinkIcon, GithubIcon, PackageIcon } from 'lucide-react';
import type { Metadata } from 'next';
import Link from 'next/link';
import { notFound } from 'next/navigation';

interface PluginDetailPageProps {
  params: Promise<{ owner: string; name: string }>;
}

export async function generateMetadata({
  params,
}: PluginDetailPageProps): Promise<Metadata | undefined> {
  const { owner, name } = await params;
  const plugin = await findCursorPlugin(owner, name);
  if (!plugin) return undefined;
  return constructMetadata({
    title: `${plugin.displayName} by ${plugin.publisher.displayName ?? plugin.publisher.name}`,
    description: plugin.description || `Cursor plugin ${plugin.displayName}.`,
    locale: 'en',
    pathname: `/plugins/${owner}/${name}`,
  });
}

export default async function PluginDetailPage({
  params,
}: PluginDetailPageProps) {
  const { owner, name } = await params;
  const plugin = await findCursorPlugin(owner, name);
  if (!plugin) notFound();

  const installCommand = `npx ai-pkgs plugins add ${owner}/${plugin.repo}`;
  const avatarFallback = (
    plugin.publisher.displayName ??
    plugin.publisher.name ??
    plugin.name
  )
    .slice(0, 2)
    .toUpperCase();

  return (
    <div className="mx-auto min-h-screen max-w-6xl px-4 py-6 sm:px-6 sm:py-12 lg:px-8">
      <Breadcrumb>
        <BreadcrumbList className="mb-6 flex-nowrap overflow-hidden font-mono text-xs">
          <BreadcrumbItem className="shrink-0">
            <BreadcrumbLink asChild>
              <Link href="/">skills</Link>
            </BreadcrumbLink>
          </BreadcrumbItem>
          <BreadcrumbSeparator />
          <BreadcrumbItem className="shrink-0">
            <BreadcrumbLink asChild>
              <Link href="/?tab=plugins">plugins</Link>
            </BreadcrumbLink>
          </BreadcrumbItem>
          <BreadcrumbSeparator />
          <BreadcrumbItem className="min-w-0">
            <BreadcrumbLink asChild>
              <Link
                className="truncate text-muted-foreground"
                href={`/plugins/${encodeURIComponent(owner)}`}
              >
                {owner}
              </Link>
            </BreadcrumbLink>
          </BreadcrumbItem>
          <BreadcrumbSeparator />
          <BreadcrumbItem className="min-w-0">
            <BreadcrumbPage className="truncate">{plugin.name}</BreadcrumbPage>
          </BreadcrumbItem>
        </BreadcrumbList>
      </Breadcrumb>

      <div className="mb-6 flex items-center gap-4">
        <Avatar className="size-14 border border-border">
          {plugin.publisher.logoUrl ? (
            <AvatarImage
              src={plugin.publisher.logoUrl}
              alt={`${plugin.publisher.displayName ?? plugin.publisher.name} avatar`}
            />
          ) : (
            <AvatarImage
              src={`https://github.com/${owner}.png`}
              alt={`${owner} avatar`}
            />
          )}
          <AvatarFallback className="font-mono text-xs uppercase">
            {avatarFallback}
          </AvatarFallback>
        </Avatar>
        <div className="min-w-0 flex-1">
          <h1 className="text-3xl font-semibold tracking-tight text-foreground text-pretty">
            {plugin.displayName}
          </h1>
          <p className="font-mono text-muted-foreground text-sm">
            @{plugin.publisher.name}
          </p>
        </div>
      </div>

      <section className="mb-8">
        <InstallCommand command={installCommand} />
      </section>

      {plugin.description ? (
        <p className="mb-10 max-w-3xl text-muted-foreground text-sm leading-6">
          {plugin.description}
        </p>
      ) : null}

      <div className="grid grid-cols-1 gap-10 lg:grid-cols-12 lg:gap-16">
        <div className="min-w-0 overflow-hidden lg:col-span-9">
          <section>
            <div className="mb-4 border-b border-border pb-4 font-mono text-sm font-medium uppercase text-foreground">
              Skills ({plugin.skills.length})
