            <div className="flex flex-col">
              {plugin.skills.length === 0 ? (
                <p className="py-8 text-center text-muted-foreground text-sm">
                  This plugin does not declare any skills.
                </p>
              ) : (
                plugin.skills.map((skill) => {
                  const Card = skill.sourceUrl ? 'a' : 'div';
                  return (
                    <Card
                      key={skill.name}
                      {...(skill.sourceUrl
                        ? {
                            href: skill.sourceUrl,
                            target: '_blank',
                            rel: 'noopener noreferrer',
                          }
                        : {})}
                      className="group flex items-start justify-between gap-4 border-b border-border/50 px-4 py-4 transition-colors hover:bg-muted/30"
                    >
                      <div className="min-w-0 flex-1">
                        <div className="flex items-center gap-2 font-semibold text-foreground">
                          <PackageIcon className="size-4 shrink-0 text-muted-foreground" />
                          <span className="truncate">{skill.name}</span>
                        </div>
                        {skill.description ? (
                          <p className="mt-1 line-clamp-2 text-sm text-muted-foreground">
                            {skill.description}
                          </p>
                        ) : null}
                      </div>
                      {skill.sourceUrl ? (
                        <ExternalLinkIcon className="size-4 shrink-0 text-muted-foreground transition-colors group-hover:text-foreground" />
                      ) : null}
                    </Card>
                  );
                })
              )}
            </div>
          </section>
        </div>

        <aside className="flex flex-col gap-6 lg:col-span-3">
          <section className="bg-background">
            <h2 className="mb-3 font-mono text-sm font-medium uppercase text-foreground">
              Repository
            </h2>
            <a
              href={plugin.repositoryUrl}
              target="_blank"
              rel="noreferrer"
              className="flex items-center gap-2 break-all font-mono text-foreground text-sm underline-offset-4 hover:underline"
            >
              <GithubIcon className="size-4 shrink-0 text-muted-foreground" />
              <span>
                {owner}/{plugin.repo}
              </span>
            </a>
          </section>

          {plugin.publisher.websiteUrl ? (
            <section className="bg-background">
              <h2 className="mb-3 font-mono text-sm font-medium uppercase text-foreground">
                Publisher
              </h2>
              <a
                href={plugin.publisher.websiteUrl}
                target="_blank"
                rel="noreferrer"
                className="flex items-center gap-2 break-all text-foreground text-sm underline-offset-4 hover:underline"
              >
                <ExternalLinkIcon className="size-4 shrink-0 text-muted-foreground" />
                <span>
                  {plugin.publisher.displayName ?? plugin.publisher.name}
                </span>
              </a>
            </section>
          ) : null}
        </aside>
      </div>
    </div>
  );
}

