import { getDb } from '@/db';
import { pageViewEvent } from '@/db/app.schema';
import { NextResponse } from 'next/server';

export const dynamic = 'force-dynamic';

const CST_OFFSET_MS = 8 * 60 * 60 * 1000;

function todayCST(): string {
  return new Date(Date.now() + CST_OFFSET_MS).toISOString().slice(0, 10);
}

interface TrackBody {
  path?: string;
  visitorId?: string;
  referrer?: string;
}

export async function POST(request: Request) {
  try {
    const body: TrackBody = await request.json();
    const path = body.path || '/';
    const visitorId =
      body.visitorId ||
      request.headers.get('x-forwarded-for') ||
      'unknown';
    const referrer = body.referrer || null;
    const day = todayCST();

    const db = await getDb();
    await db.insert(pageViewEvent).values({
      visitorId,
      path,
      day,
      referrer,
    });

    return NextResponse.json({ tracked: true });
  } catch (error) {
    console.error('[analytics/track] insert failed', error);
    return NextResponse.json({ tracked: false }, { status: 500 });
  }
}

'use client';

import { usePathname } from 'next/navigation';
import { useEffect, useRef } from 'react';

function getVisitorId(): string {
  const KEY = 'ai_skills_vid';
  try {
    const existing = localStorage.getItem(KEY);
    if (existing) return existing;
    const id = crypto.randomUUID();
    localStorage.setItem(KEY, id);
    return id;
  } catch {
    return crypto.randomUUID();
  }
}

export function TrackPageView() {
  const pathname = usePathname();
  const lastTracked = useRef<string | null>(null);

  useEffect(() => {
    if (pathname === lastTracked.current) return;
    lastTracked.current = pathname;

    const visitorId = getVisitorId();
    const body = JSON.stringify({
      path: pathname,
      visitorId,
      referrer: document.referrer || undefined,
    });

    if (navigator.sendBeacon) {
      navigator.sendBeacon(
        '/api/analytics/track',
        new Blob([body], { type: 'application/json' })
      );
    } else {
      fetch('/api/analytics/track', {
        method: 'POST',
        body,
        headers: { 'Content-Type': 'application/json' },
        keepalive: true,
      }).catch(() => {});
    }
  }, [pathname]);

  return null;
}

