import { getDb } from '@/db';
import { pageViewEvent } from '@/db/app.schema';
import { sql } from 'drizzle-orm';
import { NextResponse } from 'next/server';

export const dynamic = 'force-dynamic';

const CST_OFFSET_MS = 8 * 60 * 60 * 1000;

function todayCST(): string {
  return new Date(Date.now() + CST_OFFSET_MS).toISOString().slice(0, 10);
}

function daysAgoCST(days: number): string {
  const d = new Date(Date.now() + CST_OFFSET_MS);
  d.setUTCDate(d.getUTCDate() - days);
  return d.toISOString().slice(0, 10);
}

export async function GET(request: Request) {
  try {
    const url = new URL(request.url);
    const days = Math.min(Number(url.searchParams.get('days')) || 30, 90);

    const db = await getDb();
    const today = todayCST();
    const fromDate = daysAgoCST(days);

    const [todayStats, trend, topPaths] = await Promise.all([
      db
        .select({
          pv: sql<number>`count(*)::int`,
          uv: sql<number>`count(distinct ${pageViewEvent.visitorId})::int`,
        })
        .from(pageViewEvent)
        .where(sql`${pageViewEvent.day} = ${today}`),

      db
        .select({
          date: pageViewEvent.day,
          pv: sql<number>`count(*)::int`,
          uv: sql<number>`count(distinct ${pageViewEvent.visitorId})::int`,
        })
        .from(pageViewEvent)
        .where(
          sql`${pageViewEvent.day} >= ${fromDate} AND ${pageViewEvent.day} <= ${today}`
        )
        .groupBy(pageViewEvent.day)
        .orderBy(pageViewEvent.day),

      db
        .select({
          path: pageViewEvent.path,
          pv: sql<number>`count(*)::int`,
          uv: sql<number>`count(distinct ${pageViewEvent.visitorId})::int`,
        })
        .from(pageViewEvent)
        .where(
          sql`${pageViewEvent.day} >= ${fromDate} AND ${pageViewEvent.day} <= ${today}`
        )
        .groupBy(pageViewEvent.path)
        .orderBy(sql`count(*) desc`)
        .limit(50),
    ]);

    const todayPV = todayStats[0]?.pv ?? 0;
    const todayUV = todayStats[0]?.uv ?? 0;
    const totalPV = trend.reduce((sum, r) => sum + r.pv, 0);
    const totalUV = trend.reduce((sum, r) => sum + r.uv, 0);

    return NextResponse.json({
      todayPV,
      todayUV,
      totalPV,
      totalUV,
      period: `${fromDate} ~ ${today}`,
      trend,
      topPaths,
    });
  } catch (error) {
    console.error('[analytics/summary]', error);
    return NextResponse.json(
      { error: 'Failed to load analytics' },
      { status: 500 }
    );
  }
}

