import { readFile, writeFile } from 'node:fs/promises';
import { resolve } from 'node:path';
import journal from '../src/db/migrations/meta/_journal.json';

const migrationsDir = resolve(import.meta.dir, '../src/db/migrations');
const outPath = resolve(import.meta.dir, '../src/db/migrations.bundle.ts');

const entries = [];

for (const entry of journal.entries) {
  const sql = await readFile(resolve(migrationsDir, `${entry.tag}.sql`), 'utf8');
  entries.push({
    tag: entry.tag,
    when: entry.when,
    sql,
  });
}

const contents = `/* eslint-disable */
// Generated by scripts/bundle-migrations.ts — do not edit manually.
export const bundledMigrations = ${JSON.stringify(entries, null, 2)} as const;
`;

await writeFile(outPath, contents);
console.log(`Bundled ${entries.length} migrations → src/db/migrations.bundle.ts`);

import { bundledMigrations } from '@/db/migrations.bundle';
import type { getDb } from '@/db';
import { sql } from 'drizzle-orm';

async function sha256(text: string) {
  const data = new TextEncoder().encode(text);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return Array.from(new Uint8Array(hash))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

function splitStatements(migrationSql: string) {
  return migrationSql
    .split('--> statement-breakpoint')
    .map((statement) => statement.trim())
    .filter(Boolean);
}

/**
 * Applies bundled Drizzle SQL migrations through Hyperdrive. Safe to call
 * multiple times — already-applied migrations are skipped via
 * __drizzle_migrations.
 */
export async function runBundledMigrations(db: Awaited<ReturnType<typeof getDb>>) {
  await db.execute(sql`
    CREATE TABLE IF NOT EXISTS "__drizzle_migrations" (
      id SERIAL PRIMARY KEY,
      hash text NOT NULL,
      created_at bigint
    )
  `);

  const applied: string[] = [];
  const skipped: string[] = [];

  for (const migration of bundledMigrations) {
    const hash = await sha256(migration.sql);
    const existing = await db.execute(sql`
      SELECT id FROM "__drizzle_migrations" WHERE hash = ${hash} LIMIT 1
    `);
    const rows = Array.from(existing as Iterable<{ id: number }>);

    if (rows.length > 0) {
      skipped.push(migration.tag);
      continue;
    }

    for (const statement of splitStatements(migration.sql)) {
      await db.execute(sql.raw(statement));
    }

    await db.execute(sql`
      INSERT INTO "__drizzle_migrations" (hash, created_at)
      VALUES (${hash}, ${migration.when})
    `);
    applied.push(migration.tag);
  }

  return { applied, skipped };
}

import { getDb } from '@/db';
import { runBundledMigrations } from '@/db/run-migrations';
import { ADMIN_DB_COOKIE, verifyAdminToken } from '@/lib/admin-auth';
import { cookies } from 'next/headers';
import { NextResponse } from 'next/server';

export const dynamic = 'force-dynamic';

export async function POST() {
  const cookieStore = await cookies();
  const token = REDACTED.get(ADMIN_DB_COOKIE)?.value;
  if (!token || !(await verifyAdminToken(token))) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const db = await getDb();
    const result = await runBundledMigrations(db);
    return NextResponse.json({ success: true, ...result });
  } catch (error) {
    console.error('[admin/migrate]', error);
    return NextResponse.json(
      {
        error: 'Migration failed',
        message: error instanceof Error ? error.message : String(error),
      },
      { status: 500 }
    );
  }
}
